}

var languages = map[string]languageSpec{
	"go": {
		Language:       "go",
		BuildpackID:    "paketo-buildpacks/go",
		DetectionFiles: []string{"go.mod"},
		RequiredFiles:  []string{"go.mod", "main.go or cmd/*/main.go"},
		RecommendedFiles: []string{"go.sum"},
