		RequiredFiles:  []string{"package.json", "server.js or index.js or app.js"},
		RecommendedFiles: []string{"package-lock.json", ".node-version"},
		EnvVars:        map[string]string{"PORT": "8080", "NODE_ENV": "production"},
	},
	"python": {
