		Description: "Structured language specification — buildpack ID, detection files, required/recommended files, and environment variables.",
		MIMEType:    "application/json",
	}, func(ctx context.Context, req *gomcp.ReadResourceRequest) (*gomcp.ReadResourceResult, error) {
		// Extract language from URI: iaf://languages/<language>
		uri := req.Params.URI
		lang := ""
		if idx := strings.LastIndex(uri, "/"); idx >= 0 {
			lang = strings.ToLower(uri[idx+1:])
		}

		canonical, ok := langAliases[lang]
		if !ok {
			return nil, gomcp.ResourceNotFoundError(uri)
		}

		spec, ok := languages[canonical]
		if !ok {
			return nil, gomcp.ResourceNotFoundError(uri)
		}

		data, err := json.MarshalIndent(spec, "", "  ")
		if err != nil {
			return nil, fmt.Errorf("marshaling language spec: %w", err)
		}

		return &gomcp.ReadResourceResult{
			Contents: []*gomcp.ResourceContents{
				{URI: uri, MIMEType: "application/json", Text: string(data)},
			},
		}, nil
	})
}

package coach

import (
	"context"
	"embed"
	"encoding/json"
	"fmt"
	"io"
	"io/fs"
	"strings"

	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
)

//go:embed all:scaffolds
var scaffoldEmbedFS embed.FS

// allowedFrameworks is the allowlist of supported scaffold names.
// The raw URI segment is validated against this list before any FS access.
var allowedFrameworks = map[string]bool{
	"nextjs": true,
	"html":   true,
}

// RegisterScaffoldResource registers the iaf://scaffold/{framework} resource
// template. The handler walks the embedded FS for the validated framework and
// returns a JSON file map that agents can pass directly to push_code.
func RegisterScaffoldResource(server *gomcp.Server, deps *Dependencies) {
	server.AddResourceTemplate(&gomcp.ResourceTemplate{
		URITemplate: "iaf://scaffold/{framework}",
		Name:        "scaffold",
		Description: "UI scaffold file map for a given framework (nextjs or html). Returns a {\"path\": \"content\"} JSON object ready to pass to push_code.",
		MIMEType:    "application/json",
	}, func(ctx context.Context, req *gomcp.ReadResourceRequest) (*gomcp.ReadResourceResult, error) {
		uri := req.Params.URI

		// Extract and validate the framework segment — never pass raw URI to FS.
		framework := strings.TrimPrefix(uri, "iaf://scaffold/")
		if !allowedFrameworks[framework] {
			supported := []string{"nextjs", "html"}
			return nil, fmt.Errorf("unknown scaffold framework %q; supported: %s", framework, strings.Join(supported, ", "))
		}

		fsRoot := "scaffolds/" + framework
		files, err := collectFiles(scaffoldEmbedFS, fsRoot)
		if err != nil {
			return nil, fmt.Errorf("reading scaffold %q: %w", framework, err)
		}

		data, err := json.MarshalIndent(files, "", "  ")
		if err != nil {
			return nil, fmt.Errorf("marshaling scaffold: %w", err)
		}

		return &gomcp.ReadResourceResult{
			Contents: []*gomcp.ResourceContents{
				{URI: uri, MIMEType: "application/json", Text: string(data)},
			},
		}, nil
	})
}

// collectFiles walks fsys rooted at root and returns a map of
// relative-path → file-content for all regular files.
func collectFiles(fsys embed.FS, root string) (map[string]string, error) {
	files := make(map[string]string)
	prefix := root + "/"

	err := fs.WalkDir(fsys, root, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			return nil
		}

		f, err := fsys.Open(path)
		if err != nil {
			return fmt.Errorf("open %q: %w", path, err)
		}
		defer f.Close()

		data, err := io.ReadAll(f)
		if err != nil {
			return fmt.Errorf("read %q: %w", path, err)
		}

		// Strip the "scaffolds/{framework}/" prefix so agents receive
		// "pages/index.js" not "scaffolds/nextjs/pages/index.js".
		key := strings.TrimPrefix(path, prefix)
		files[key] = string(data)
		return nil
	})
	return files, err
}

package main

import (
	"context"
	"log/slog"
	"os"

	"github.com/dlapiduz/iaf/internal/mcp/coach"
	"github.com/dlapiduz/iaf/internal/orgstandards"
	gomcp "github.com/modelcontextprotocol/go-sdk/mcp"
)

func main() {
	logger := slog.New(slog.NewJSONHandler(os.Stderr, nil))
	slog.SetDefault(logger)

	token := os.Getenv("COACH_API_TOKEN")
	if token == "" {
		logger.Error("COACH_API_TOKEN is required — refusing to start without auth (an unauthenticated coach leaks org standards)")
		os.Exit(1)
	}

	deps := &coach.Dependencies{
		BaseDomain:           os.Getenv("COACH_BASE_DOMAIN"),
		LoggingStandardsFile: os.Getenv("COACH_LOGGING_STANDARDS_FILE"),
		MetricsStandardsFile: os.Getenv("COACH_METRICS_STANDARDS_FILE"),
		TracingStandardsFile: os.Getenv("COACH_TRACING_STANDARDS_FILE"),
	}

	orgFile := os.Getenv("COACH_ORG_STANDARDS_FILE")
	orgLoader := orgstandards.New(orgFile, logger)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	go orgLoader.Start(ctx)
	deps.OrgStandards = orgLoader

	server := coach.NewServer(deps)

	logger.Info("starting coach MCP server", "transport", "stdio")

	transport := &gomcp.StdioTransport{}
	if _, err := server.Connect(ctx, transport, nil); err != nil {
		logger.Error("failed to connect coach MCP server", "error", err)
		os.Exit(1)
	}

	// Block until stdin is closed
	select {}
}

